INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Distinguish a random error from a systematic error.', 'A random error causes scatter about the true value (read by repeating and averaging); a systematic error causes a consistent shift away from the true value (e.g. zero error on a balance) and cannot be reduced by repetition.', 1, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Define precision and accuracy.', 'Accuracy is how close a measured value is to the true value. Precision is how close repeated readings are to each other (small spread), independent of accuracy.', 2, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'How is absolute uncertainty in a single reading estimated?', 'Half the smallest scale division for an analogue instrument, or ±1 in the last digit for a digital one. For a repeated set, use half the range.', 3, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'How are percentage uncertainties combined when quantities are multiplied or divided?', 'They are added. So in P = IV, %u(P) = %u(I) + %u(V).', 4, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'How does uncertainty propagate through a power, e.g. V = (4/3)πr^3?', 'Multiply the percentage uncertainty in the base by the power: %u(V) = 3 × %u(r).', 5, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Convert 1 GeV to joules.', '1 eV = 1.60 × 10^-19 J, so 1 GeV = 10^9 × 1.60 × 10^-19 = 1.60 × 10^-10 J.', 6, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'List the seven SI base units.', 'metre (m), kilogram (kg), second (s), ampere (A), kelvin (K), mole (mol), candela (cd).', 7, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Derive the SI units of the joule from base units.', 'J = N m = (kg m s^-2)(m) = kg m^2 s^-2.', 8, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'What does it mean for an equation to be "homogeneous" in units?', 'Each additive term has the same SI units. A homogeneous equation may still be wrong, but a non-homogeneous equation is definitely wrong.', 9, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'When should results be reported to a particular number of significant figures?', 'The answer should not exceed the precision of the least precise input — usually the data with the fewest significant figures.', 10, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Define the unit "light-year".', 'The distance light travels in vacuum in one year ≈ 9.46 × 10^15 m. It is a unit of distance, not time.', 11, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'How is the gradient of a best-fit line used to find an uncertainty?', 'Draw the steepest and shallowest reasonable lines through the error bars; half the difference between their gradients gives the uncertainty in the gradient.', 12, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'A ruler has zero error +0.2 mm. Is this random or systematic?', 'Systematic — every reading is offset by the same +0.2 mm. It is corrected by subtracting the zero error, not by averaging.', 13, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Why is using a fiducial marker good experimental practice when timing oscillations?', 'It marks the equilibrium position so the timer starts and stops at the same point in each cycle, reducing random timing error and ensuring whole oscillations are counted.', 14, 'alevel'),
  ('Physics', 'AQA', '3.1', 'Measurements and Their Errors', 'Convert 25 °C to kelvin.', 'T(K) = θ(°C) + 273.15, so 25 °C = 298.15 K.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'What does the notation ^A_Z X tell you about a nuclide?', 'A is the nucleon (mass) number = protons + neutrons; Z is the proton (atomic) number; A − Z gives the neutron number.', 1, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'Define specific charge.', 'Charge per unit mass, Q/m, with units C kg^-1. The proton has 9.58 × 10^7 C kg^-1; the electron 1.76 × 10^11 C kg^-1.', 2, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'List the four fundamental forces and their exchange particles.', 'Strong (gluon), electromagnetic (virtual photon), weak (W± and Z bosons), gravity (graviton, hypothetical).', 3, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'Give the quark composition of a proton and a neutron.', 'Proton = uud (charge = +2/3 + 2/3 − 1/3 = +1). Neutron = udd (charge = +2/3 − 1/3 − 1/3 = 0).', 4, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'What is a hadron and how are hadrons subdivided?', 'A particle that experiences the strong force. Subdivided into baryons (3 quarks, e.g. proton, neutron) and mesons (a quark + antiquark, e.g. pion, kaon).', 5, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'What are leptons and give three examples.', 'Fundamental particles that do not feel the strong force. Examples: electron, muon, tau, plus their associated neutrinos and antiparticles.', 6, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'State the conservation laws obeyed in all particle interactions.', 'Conservation of charge, baryon number, lepton number (per family), and energy/momentum. Strangeness is conserved in strong/EM but can change by ±1 in weak interactions.', 7, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'Write the equation for β− decay of a neutron at the quark level.', 'n → p + e− + ν̄_e, equivalently d → u + W− → u + e− + ν̄_e.', 8, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'What is the photoelectric effect?', 'Emission of electrons from a metal surface when illuminated by light above a threshold frequency f0. Below f0 no electrons are emitted however intense the light.', 9, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'State Einstein''s photoelectric equation.', 'hf = φ + KE_max, where hf is photon energy, φ is the work function and KE_max is the maximum kinetic energy of emitted photoelectrons.', 10, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'Why does the wave model fail to explain the photoelectric effect?', 'Wave theory predicts energy depends on intensity, so any frequency given enough intensity should eject electrons after a build-up time. Experimentally, frequency must exceed f0 and emission is instantaneous — explained only by photons of energy hf.', 11, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'What is fluorescence in a discharge tube?', 'High-energy electrons collide with atoms, exciting bound electrons to higher levels. When they fall back, photons of specific frequencies are emitted, giving a line spectrum.', 12, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'State the de Broglie wavelength formula.', 'λ = h/p = h/(mv). The wavelength associated with a particle of momentum p, demonstrating wave-particle duality.', 13, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'Why is electron diffraction evidence for de Broglie''s hypothesis?', 'A beam of electrons accelerated through a thin graphite film produces a diffraction pattern of concentric rings — wave behaviour from particles, with spacing matching λ = h/p.', 14, 'alevel'),
  ('Physics', 'AQA', '3.2', 'Particles and Radiation', 'What is annihilation and what is its minimum photon energy?', 'When a particle meets its antiparticle, both are converted entirely to electromagnetic radiation. Minimum photon energy = rest energy of one particle, e.g. 0.511 MeV for an e− e+ pair (two photons emitted back-to-back).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.3', 'Waves', 'Distinguish a transverse wave from a longitudinal wave.', 'In a transverse wave the particle oscillation is perpendicular to the direction of energy transfer (e.g. light, water waves). In a longitudinal wave it is parallel (e.g. sound). <svg viewBox="0 0 200 80" width="180" height="70" style="display:block;margin:6px auto"><path d="M10,40 Q35,10 60,40 T110,40 T160,40 T190,40" fill="none" stroke="#0B1E3F" stroke-width="2"/><line x1="60" y1="10" x2="60" y2="70" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2,2"/><line x1="110" y1="10" x2="110" y2="70" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2,2"/><text x="78" y="78" font-size="9" fill="#0B1E3F">λ</text></svg>', 1, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'Define the period, frequency and wavelength of a wave.', 'Period T = time for one complete oscillation (s). Frequency f = oscillations per second = 1/T (Hz). Wavelength λ = distance between adjacent points in phase (m).', 2, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'Write the wave speed equation.', 'c = fλ. The speed of a wave equals frequency times wavelength.', 3, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'What is meant by polarisation, and which type of wave can be polarised?', 'Polarisation restricts the oscillations to one plane only. Only transverse waves can be polarised — evidence that light is transverse but sound is not.', 4, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'State the principle of superposition.', 'When two or more waves overlap, the resultant displacement at any point is the vector sum of the individual displacements at that instant.', 5, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'What conditions are required for two sources to be coherent?', 'They must have a constant phase difference and the same frequency (and ideally the same amplitude). Without coherence, interference patterns are not stable.', 6, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'State the path-difference conditions for constructive and destructive interference.', 'Constructive: path difference = nλ. Destructive: path difference = (n + 1/2)λ, where n is an integer.', 7, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'State the Young''s double-slit fringe-spacing formula.', 'w = λD/s, where w is fringe spacing, λ is wavelength, D is slit-to-screen distance, s is slit separation.', 8, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'What is the diffraction-grating equation?', 'd sin θ = nλ, where d is the slit spacing, θ is the angle from the normal to the n-th order maximum.', 9, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'How does diffraction depend on the slit-to-wavelength ratio?', 'Significant diffraction occurs when the slit width is comparable to the wavelength. Narrower slits (or longer λ) give wider, more pronounced diffraction.', 10, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'What is a stationary wave and how does it form?', 'A wave formed by superposition of two waves of equal frequency and amplitude travelling in opposite directions, producing fixed nodes (zero amplitude) and antinodes (maximum amplitude). No net energy is transferred.', 11, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'Give the frequency of the n-th harmonic on a string fixed at both ends.', 'f_n = nv/(2L), where v is wave speed and L is the string length. n=1 is the fundamental.', 12, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'State Snell''s law.', 'n1 sin θ1 = n2 sin θ2, where n is refractive index. Light bends toward the normal entering a denser medium.', 13, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'Define critical angle and give the formula.', 'The angle of incidence (in the denser medium) above which total internal reflection occurs. sin θc = n2/n1, where n1 > n2.', 14, 'alevel'),
  ('Physics', 'AQA', '3.3', 'Waves', 'Why does an optical fibre use cladding with a lower refractive index than the core?', 'So that light striking the core-cladding boundary above the critical angle undergoes total internal reflection, keeping signals confined within the core with minimal loss.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Distinguish a scalar from a vector.', 'A scalar has magnitude only (mass, energy, speed). A vector has magnitude and direction (displacement, velocity, force).', 1, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'How are two perpendicular forces combined into a resultant?', 'Magnitude R = √(F1^2 + F2^2); direction θ = tan^-1(F2/F1) from F1.', 2, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'State the principle of moments.', 'For a body in rotational equilibrium, the sum of clockwise moments about any point equals the sum of anticlockwise moments. Moment = force × perpendicular distance.', 3, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Write the four SUVAT equations.', 'v = u + at;  s = ut + (1/2)at^2;  v^2 = u^2 + 2as;  s = (u+v)t/2. Valid only for constant acceleration.', 4, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'A projectile is launched at angle θ with speed v. State the time of flight on level ground.', 't = 2v sin θ / g. Range R = v^2 sin(2θ)/g; maximum range at θ = 45°.', 5, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'State Newton''s three laws of motion.', '1) An object remains at rest or constant velocity unless acted on by a net force. 2) F = ma (net force = mass × acceleration). 3) Every action has an equal and opposite reaction on a different body.', 6, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Define momentum and state the principle of conservation.', 'p = mv (kg m s^-1). In a closed system with no external forces, total momentum is conserved before and after any interaction.', 7, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Distinguish elastic and inelastic collisions.', 'Both conserve momentum. Elastic also conserves kinetic energy; inelastic loses KE to heat, sound or deformation. Perfectly inelastic: objects stick together.', 8, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Define impulse and state its relationship to momentum.', 'Impulse = F × t = ∫F dt = change in momentum (Δp). Long contact time reduces force for a given Δp — basis of crumple zones, airbags.', 9, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Define work done by a constant force.', 'W = Fs cos θ, where θ is the angle between force and displacement. SI unit joule = N m.', 10, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'State Hooke''s law and its limit.', 'F = kx — extension is proportional to applied force up to the limit of proportionality. Beyond this, the relationship is no longer linear.', 11, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Define the Young modulus.', 'E = stress/strain = (F/A)/(ΔL/L), measured in pascals. It is a property of the material, independent of dimensions.', 12, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Sketch a typical stress-strain curve for a ductile metal and label key points.', 'Linear up to limit of proportionality, then elastic limit, yield point (sudden strain), plastic region, ultimate tensile stress, then necking and fracture. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><line x1="20" y1="100" x2="190" y2="100" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="100" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,100 L70,40 Q90,30 110,32 Q140,35 160,55 L175,90" fill="none" stroke="#0B1E3F" stroke-width="2"/><circle cx="70" cy="40" r="2" fill="#0B1E3F"/><text x="55" y="34" font-size="8" fill="#0B1E3F">Y</text><circle cx="110" cy="32" r="2" fill="#0B1E3F"/><text x="115" y="28" font-size="8" fill="#0B1E3F">UTS</text><text x="100" y="115" font-size="9" fill="#0B1E3F">strain</text><text x="2" y="60" font-size="9" fill="#0B1E3F">σ</text></svg>', 13, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'How is elastic strain energy calculated for a wire obeying Hooke''s law?', 'E = (1/2)Fx = (1/2)kx^2 — the area under the force-extension graph.', 14, 'alevel'),
  ('Physics', 'AQA', '3.4', 'Mechanics and Materials', 'Distinguish brittle and ductile materials.', 'Brittle materials (glass, ceramics) fracture at the elastic limit with little plastic deformation. Ductile materials (copper, mild steel) can be drawn into wires, undergoing significant plastic flow before fracture.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.5', 'Electricity', 'Define electric current.', 'The rate of flow of electric charge: I = ΔQ/Δt. Measured in amperes (A); 1 A = 1 C s^-1.', 1, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Define potential difference.', 'The work done per unit charge moved between two points: V = W/Q. Unit: volt = J C^-1.', 2, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'State Ohm''s law.', 'For an ohmic conductor at constant temperature, V = IR — the current is directly proportional to the potential difference.', 3, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Define resistivity.', 'ρ = RA/L, the resistance of unit cube of a material. Units: Ω m. It is a property of the material at a given temperature.', 4, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Sketch the I-V characteristic of a filament lamp.', 'Curve through the origin, steeper near the origin (low T, low R) and flatter at higher V — resistance rises as the filament heats up. <svg viewBox="0 0 160 110" width="150" height="100" style="display:block;margin:6px auto"><line x1="80" y1="10" x2="80" y2="100" stroke="#0B1E3F" stroke-width="1"/><line x1="10" y1="55" x2="150" y2="55" stroke="#0B1E3F" stroke-width="1"/><path d="M15,90 Q40,75 70,60 Q80,56 90,52 Q120,42 145,30" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="135" y="68" font-size="9" fill="#0B1E3F">V</text><text x="84" y="18" font-size="9" fill="#0B1E3F">I</text></svg>', 5, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'How does the resistance of a thermistor vary with temperature?', 'For an NTC thermistor, resistance decreases with increasing temperature — more charge carriers are released as the semiconductor heats up.', 6, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'State the rules for resistors in series and in parallel.', 'Series: R_total = R1 + R2 + ... Parallel: 1/R_total = 1/R1 + 1/R2 + ... Parallel always gives a smaller total than the smallest individual resistor.', 7, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'State Kirchhoff''s two laws.', '1) The sum of currents into any junction equals the sum out (charge conservation). 2) The sum of EMFs around a loop equals the sum of pd''s across components (energy conservation).', 8, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Write three forms of electrical power.', 'P = IV = I^2R = V^2/R. Energy dissipated W = Pt.', 9, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Define EMF and internal resistance.', 'EMF (ε) is the energy supplied by a source per coulomb of charge. Internal resistance (r) is the small resistance of the source itself; terminal pd V = ε − Ir.', 10, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Why does the terminal pd of a battery fall as more current is drawn?', 'Because more "lost volts" Ir are dropped across the internal resistance, so V = ε − Ir falls.', 11, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'How does a potential divider work?', 'Two resistors in series across a supply. The output voltage taken across one resistor is V_out = V_in × R2/(R1 + R2). Replacing one resistor with a sensor gives a sensor circuit (LDR, thermistor).', 12, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'What is the use of an LDR in a potential divider?', 'Resistance falls with increasing light, so the divider output changes with light intensity — used in light-dependent switches and automatic dimmers.', 13, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'How are EMF and internal resistance found graphically?', 'Plot V (terminal pd) against I. The y-intercept is ε; the gradient is −r.', 14, 'alevel'),
  ('Physics', 'AQA', '3.5', 'Electricity', 'Why do household appliances connect in parallel rather than in series?', 'Each appliance gets the full mains voltage, can be switched independently, and the failure of one device does not break the circuit for the others.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Define angular speed.', 'ω = Δθ/Δt = 2π/T = 2πf, in rad s^-1. Linear speed v = rω.', 1, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'State the centripetal acceleration formula.', 'a = v^2/r = ω^2 r, directed toward the centre. Required because the velocity vector continually changes direction.', 2, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'What provides the centripetal force for a car cornering on a flat road?', 'Friction between the tyres and the road. If the required centripetal force exceeds the maximum static friction, the car skids outward.', 3, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Define simple harmonic motion (SHM).', 'Motion in which the acceleration is proportional to displacement from equilibrium and directed toward equilibrium: a = −ω^2 x.', 4, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'For SHM with amplitude A, write x(t), v(t) and v_max.', 'x = A cos(ωt); v = −Aω sin(ωt); v_max = Aω. The particle is fastest at equilibrium and momentarily stationary at x = ±A.', 5, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'State the period of a simple pendulum.', 'T = 2π √(L/g), valid for small angles (< ~10°), independent of mass and amplitude.', 6, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'State the period of a mass on a spring.', 'T = 2π √(m/k), where k is the spring constant. Doubling mass increases period by √2.', 7, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Distinguish free, damped and forced oscillations.', 'Free: oscillates at natural frequency, no driving force. Damped: amplitude decays due to resistive forces. Forced: oscillates at the driver frequency, regardless of natural frequency.', 8, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'What is resonance?', 'When a system is driven at its natural frequency, energy transfer is maximum and amplitude grows large. Damping reduces the resonant amplitude.', 9, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Define specific heat capacity.', 'The energy required to raise the temperature of 1 kg of a substance by 1 K: Q = mcΔθ. Units: J kg^-1 K^-1.', 10, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Define specific latent heat.', 'The energy required per kg to change a substance''s phase without temperature change: Q = mL. L_f for fusion (solid↔liquid), L_v for vaporisation (liquid↔gas).', 11, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'State the ideal gas equation in two forms.', 'pV = nRT (R = 8.31 J K^-1 mol^-1) and pV = NkT (k = 1.38 × 10^-23 J K^-1, N = number of molecules).', 12, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'List the assumptions of the kinetic theory of gases.', 'Many identical molecules in random motion; volume of molecules is negligible; collisions are elastic; intermolecular forces are negligible except during collisions; collision time is negligible compared to time between collisions.', 13, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Relate temperature to mean kinetic energy of a gas molecule.', '(1/2)m<c^2> = (3/2)kT. The mean translational KE of a gas molecule is proportional to absolute temperature.', 14, 'alevel'),
  ('Physics', 'AQA', '3.6', 'Further Mechanics and Thermal Physics', 'Why does pressure rise when a gas is heated at constant volume?', 'Higher T means greater mean speed of molecules, so they hit the walls more often and harder, giving a greater rate of momentum change per unit area.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'State Newton''s law of gravitation.', 'F = −Gm1m2/r^2, where G = 6.67 × 10^-11 N m^2 kg^-2. The minus sign indicates an attractive force.', 1, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Define gravitational field strength.', 'g = F/m, the force per unit mass on a small test mass. Near Earth''s surface g ≈ 9.81 N kg^-1.', 2, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Define gravitational potential.', 'V = −GM/r, the work done per unit mass to bring a test mass from infinity to a point in the field. Always negative; zero at infinity.', 3, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'What is escape velocity and how is it derived?', 'Minimum speed at the surface for an object to reach infinity. Set (1/2)mv^2 = GMm/R, giving v_esc = √(2GM/R) ≈ 11.2 km s^-1 for Earth.', 4, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'State Kepler''s third law for a circular orbit.', 'T^2 ∝ r^3. Specifically T^2 = (4π^2/GM) r^3. Used to find planet masses or orbital periods.', 5, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'What is a geostationary orbit?', 'A circular equatorial orbit with period 24 hours, so the satellite remains above the same point on Earth. Altitude ≈ 36 000 km. Used for telecoms and TV satellites.', 6, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'State Coulomb''s law.', 'F = kQ1Q2/r^2, with k = 1/(4πε0) ≈ 8.99 × 10^9 N m^2 C^-2. Like charges repel, unlike attract.', 7, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Define electric field strength.', 'E = F/Q, force per unit positive test charge. Units: N C^-1 or V m^-1.', 8, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Compare gravitational and electric fields.', 'Both follow inverse-square laws and have analogous potential expressions. Gravity is always attractive; electric forces can be either. Gravity acts on mass; electricity acts on charge.', 9, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Define capacitance.', 'C = Q/V, the charge stored per volt. Unit: farad (F = C V^-1). For a parallel-plate capacitor C = ε0 ε_r A/d.', 10, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Give three equivalent expressions for the energy stored in a capacitor.', 'W = (1/2)QV = (1/2)CV^2 = Q^2/(2C). The factor of 1/2 arises because V grows from 0 to its final value as the capacitor charges.', 11, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Write the equations for capacitor discharge through a resistor.', 'Q = Q0 e^-t/(RC); V = V0 e^-t/(RC); I = I0 e^-t/(RC). The time constant τ = RC.', 12, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'Give the magnetic force on a current-carrying conductor.', 'F = BIL sin θ, where θ is the angle between the current and the magnetic field. Direction by Fleming''s left-hand rule.', 13, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'State Faraday''s and Lenz''s laws of electromagnetic induction.', 'Faraday: EMF = −dΦ/dt (rate of change of flux linkage). Lenz: the induced current opposes the change that produced it (sign of the minus).', 14, 'alevel'),
  ('Physics', 'AQA', '3.7', 'Fields and Their Consequences', 'How does an ideal transformer relate primary and secondary quantities?', 'V_p/V_s = N_p/N_s. For an ideal (100% efficient) transformer V_p I_p = V_s I_s, so I_p/I_s = N_s/N_p.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'What did Rutherford''s alpha-scattering experiment reveal?', 'Most alphas passed straight through gold foil, a few deflected through small angles, and very few bounced back — evidence for a tiny, dense, positively charged nucleus with mostly empty atomic space.', 1, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Give the empirical formula for nuclear radius.', 'R = R0 A^(1/3), where R0 ≈ 1.2 fm. Density of nuclear matter is therefore approximately constant.', 2, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Compare the ranges and ionising powers of α, β and γ.', 'α: highly ionising, range a few cm in air, stopped by paper. β: moderately ionising, range ~1 m in air, stopped by ~3 mm aluminium. γ: weakly ionising, range theoretically infinite, attenuated by lead/concrete.', 3, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'State the radioactive decay law.', 'dN/dt = −λN, giving N = N0 e^-λt. λ is the decay constant — probability per unit time of an individual nucleus decaying.', 4, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Relate half-life to the decay constant.', 'T_½ = ln 2 / λ. The time for half the nuclei in a sample to decay.', 5, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Define activity and its unit.', 'A = λN, the number of decays per second. Unit: becquerel (Bq) = 1 decay per second.', 6, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'How is carbon-14 dating performed?', 'Living organisms have a fixed C-14:C-12 ratio. After death, C-14 (T_½ = 5730 yr) decays. Measuring the residual ratio gives the age via t = (1/λ) ln(N0/N).', 7, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Define mass defect and binding energy.', 'Mass defect Δm = mass of separate nucleons − mass of nucleus. Binding energy = Δm c^2, the energy released when the nucleus is assembled from free nucleons (or required to fully separate them).', 8, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Why does iron-56 have the highest binding energy per nucleon?', 'The strong nuclear force saturates at ~1 fm: in light nuclei more nucleons share the binding; in very heavy nuclei electrostatic repulsion of protons reduces the binding. The peak is around A ≈ 56.', 9, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Distinguish fission from fusion.', 'Fission: a heavy nucleus splits into smaller fragments releasing energy (e.g. U-235). Fusion: light nuclei combine into a heavier nucleus releasing more energy per nucleon (e.g. H + H → He in stars).', 10, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Why does fusion require very high temperatures?', 'Positive nuclei must overcome the Coulomb repulsion barrier to come within ~1 fm where the strong force binds them. Thermal energies of millions of kelvin are needed.', 11, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'What roles do the moderator, control rods and coolant play in a fission reactor?', 'Moderator (graphite, water) slows neutrons to thermal energies for further fission. Control rods (boron, cadmium) absorb neutrons to control rate. Coolant transfers heat to the steam generator.', 12, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Why must spent nuclear fuel be stored?', 'It contains long-lived radioactive fission products and actinides emitting β/γ for thousands of years. Storage in shielded ponds and ultimately deep geological repositories is required.', 13, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Define dose equivalent.', 'H = D × Q, where D is absorbed dose (Gy = J kg^-1) and Q is a quality factor (~1 for β/γ, ~20 for α). Unit: sievert (Sv).', 14, 'alevel'),
  ('Physics', 'AQA', '3.8', 'Nuclear Physics', 'Why is alpha radiation dangerous if ingested but not externally?', 'Externally it cannot penetrate the dead skin layer. If ingested or inhaled, its very high ionisation density damages living cells severely (Q ≈ 20).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'List the seven SI base units.', 'metre (m), kilogram (kg), second (s), ampere (A), kelvin (K), mole (mol), candela (cd).', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Express the joule in SI base units.', 'J = N m = (kg m s^-2) m = kg m^2 s^-2.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Distinguish random and systematic errors.', 'Random errors cause scatter about the true value (reduced by averaging). Systematic errors offset every reading by the same amount (e.g. zero error) and cannot be reduced by repetition.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Define accuracy and precision.', 'Accuracy: how close a measurement is to the true value. Precision: how close repeated readings are to each other (small spread), independent of accuracy.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'How is uncertainty in a single reading estimated?', 'Half the smallest scale division on an analogue instrument; ±1 in the last digit on a digital one. For repeats, half the range.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'How are percentage uncertainties combined when quantities are multiplied or divided?', 'They are added: %u(P) = %u(I) + %u(V) for P = IV.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'How does uncertainty propagate through a power, e.g. V = (4/3)πr^3?', 'Multiply the percentage uncertainty in the base by the magnitude of the power: %u(V) = 3 × %u(r).', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'How is the uncertainty in a gradient found from a graph?', 'Draw the steepest and shallowest lines through the error bars; half the difference between their gradients gives the gradient uncertainty.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Why is a graph generally more useful than a table of repeats?', 'It averages out random error across many points, makes systematic offsets (non-zero intercepts) visible, and lets uncertainties be read from gradient and intercept.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'How many significant figures should a final answer be quoted to?', 'No more than the least precise input data — typically 2 or 3 SF in A-level practicals.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Why are SI units preferred over imperial units in physics?', 'They are coherent (no awkward conversion factors between derived and base units) and internationally agreed, so calculations and comparisons are unambiguous.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Define a "homogeneous" equation.', 'One in which every additive term has the same SI base units. A homogeneous equation may still be wrong, but a non-homogeneous equation is definitely wrong.', 12, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Why is reproducibility important in scientific results?', 'A result that other groups can reproduce, with their own equipment, gives confidence that systematic biases are not driving the conclusion.', 13, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'What is the role of peer review?', 'Independent experts evaluate the methods and conclusions of a paper before publication, filtering out errors and weak claims and improving rigour.', 14, 'alevel'),
  ('Physics', 'Edexcel', 'T1', 'Working as a Physicist', 'Convert 0.0042 to standard form to 2 SF.', '4.2 × 10^-3.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'Define velocity and acceleration as vectors.', 'Velocity = rate of change of displacement (m s^-1). Acceleration = rate of change of velocity (m s^-2). Both have direction; sign indicates direction relative to chosen axis.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'How do you resolve a force F at angle θ to horizontal?', 'F_x = F cos θ; F_y = F sin θ. Each component acts independently along its axis.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'A projectile is launched horizontally from height h with speed u. State equations for time of flight and range.', 't = √(2h/g); R = ut = u√(2h/g). Vertical and horizontal motions are independent.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'State Newton''s second law in its full vector form.', 'F = dp/dt = m(dv/dt) = ma when mass is constant. In rocket problems mass changes and the full form is needed.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'What is meant by terminal velocity?', 'The constant velocity reached when drag (or upthrust + drag) balances the weight, so net force = 0 and acceleration = 0.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'Define the centre of mass.', 'The point at which the total weight of a body can be considered to act. For a uniform symmetric object it lies on its axis of symmetry.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'What is the moment of a force about a pivot?', 'M = F × d, where d is the perpendicular distance from the pivot to the line of action of the force. Unit: N m.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'State the conditions for a body to be in equilibrium.', '(1) Resultant force = 0 (translational equilibrium). (2) Resultant moment about any point = 0 (rotational equilibrium).', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'Define kinetic and gravitational potential energy.', 'KE = (1/2)mv^2; GPE = mgh (near Earth''s surface). Work-energy theorem: net work done = ΔKE.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'Define power and give two equivalent equations.', 'Power = energy transferred / time = work done / time. P = W/t = Fv (for force at constant velocity). Unit: watt.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'Define efficiency and give the percentage form.', 'Efficiency = useful output / total input. As %: × 100. Wasted energy is usually heat or sound.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T2', 'Mechanics', 'State the principle of conservation of momentum.', 'In a closed system with no external resultant force, total momentum before any interaction equals total momentum after.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Define electric current in terms of charge carriers.', 'I = nAvq, where n is the number density of carriers, A is cross-sectional area, v is drift velocity and q is the charge per carrier.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Why is drift velocity so small in metals?', 'Although the current is appreciable, n (free electrons per m^3) is very large (~10^29), so v = I/(nAq) comes out at fractions of a mm s^-1.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'State Ohm''s law and the conditions under which it applies.', 'V = IR with R constant. Holds for ohmic conductors at constant temperature; fails for filament lamps, diodes and thermistors.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Sketch the I-V characteristic of a semiconductor diode.', 'Negligible current in reverse bias; sharp rise after a small forward threshold (~0.7 V for silicon); approximately linear thereafter. Strongly non-ohmic.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Define resistivity.', 'ρ = RA/L, where R is resistance of a uniform sample, A its cross-sectional area, L its length. SI unit: Ω m.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Why does resistance of a metal increase with temperature?', 'Lattice ions vibrate with greater amplitude, increasing the rate of collisions with conduction electrons and reducing their drift velocity.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Why does resistance of an NTC thermistor decrease with temperature?', 'Higher T promotes more electrons across the band gap into the conduction band, so the number density n of carriers rises faster than scattering increases.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'State Kirchhoff''s current and voltage laws.', 'KCL: ΣI_in = ΣI_out at any junction. KVL: ΣEMF = ΣIR around any closed loop.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Combine three resistors of 4 Ω, 6 Ω and 12 Ω in parallel.', '1/R = 1/4 + 1/6 + 1/12 = 3/12 + 2/12 + 1/12 = 6/12, so R = 2 Ω.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'Define EMF and explain "lost volts".', 'EMF ε = energy supplied per coulomb. Lost volts Ir is the pd dropped across internal resistance, so terminal pd V = ε − Ir.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'How does a potential divider produce a variable output?', 'V_out = V_in × R2/(R1 + R2). Replacing R2 with a variable resistor or sensor gives a tunable or sensor-driven voltage.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T3', 'Electric Circuits', 'A 100 W lamp is on for 5 hours. How much energy does it use in kWh?', 'E = 0.100 kW × 5 h = 0.5 kWh = 1.8 × 10^6 J.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T4', 'Materials', 'Define density.', 'ρ = m/V (kg m^-3). It is a property of the material, independent of size or shape.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'State Archimedes'' principle.', 'The upthrust on a body immersed in a fluid equals the weight of fluid displaced: U = ρ_fluid V g.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'State Stokes'' law and the conditions for its use.', 'F_drag = 6πηrv, valid for a small smooth sphere moving at low speed (laminar flow) through a fluid of viscosity η.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'How is terminal velocity reached for a sphere falling through a fluid?', 'Initially weight > upthrust + drag, so it accelerates. As v rises, drag rises until weight = upthrust + drag and net force = 0; v = v_term.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'State Hooke''s law.', 'For a spring or wire, extension is proportional to applied force up to the limit of proportionality: F = kx.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'Define stress, strain and the Young modulus.', 'Stress σ = F/A (Pa). Strain ε = ΔL/L (dimensionless). Young modulus E = σ/ε (Pa) — gradient of the elastic part of a stress-strain graph.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'How is elastic strain energy found from a force-extension graph?', 'It equals the area under the (linear) graph: E = (1/2)Fx = (1/2)kx^2.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'Distinguish elastic from plastic deformation.', 'Elastic: returns to original shape when force is removed. Plastic: permanent deformation remains because atomic planes have slipped past each other.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'Distinguish brittle, ductile and polymeric stress-strain behaviour.', 'Brittle: linear, fractures at elastic limit (glass). Ductile: linear elastic then long plastic region (copper). Polymeric: large strains, may show hysteresis (rubber).', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'What does a hysteresis loop on rubber tell you?', 'The area inside the loading-unloading loop equals the energy dissipated as heat per cycle — important in tyre and shock-absorber design.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'Why does a rubber band warm up when stretched and released repeatedly?', 'Each cycle dissipates the energy represented by the hysteresis loop area into thermal motion of polymer chains.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T4', 'Materials', 'Why is steel preferred to glass for railway tracks?', 'Steel is ductile and has a high Young modulus, withstanding shocks and fatigue without shattering. Glass is brittle and would fracture.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'Define amplitude, wavelength, period and frequency.', 'Amplitude: maximum displacement from equilibrium. Wavelength λ: distance between two adjacent points in phase. Period T: time for one cycle. Frequency f = 1/T.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'Define phase difference.', 'The fraction of a cycle that one oscillation lags or leads another, expressed in radians or degrees. In phase = 0 or 2π; antiphase = π.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'State the principle of superposition.', 'When two waves overlap, the resultant displacement is the algebraic (vector) sum of their individual displacements at that point.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'How are stationary waves formed on a string?', 'A wave reflected from a fixed end superposes with the incident wave; nodes form every λ/2 and antinodes between them. Resonance occurs at f_n = nv/(2L).', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'State the diffraction-grating equation.', 'd sin θ = nλ. Maxima are sharper than for two slits because more slits contribute in phase.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'Why does monochromatic light produce sharper interference patterns than white light?', 'White light contains many wavelengths producing overlapping fringe spacings (w = λD/s); monochromatic light gives one well-defined w.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'Define refractive index.', 'n = c/v, where c is the speed of light in vacuum and v in the medium. Always ≥ 1.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'State the photoelectric equation and define each term.', 'hf = φ + KE_max. hf is photon energy, φ is the work function (minimum energy to liberate an electron from the surface), KE_max is the maximum kinetic energy of emitted electrons.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'Why does intensity not affect KE_max in the photoelectric effect?', 'Each ejection involves one photon. KE_max depends on photon energy hf, not on the number of photons. Higher intensity simply means more photoelectrons, not faster ones.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'What is the de Broglie wavelength of an electron accelerated through V volts?', 'λ = h/p = h/√(2meV). For 100 V it is about 0.12 nm — comparable to atomic spacings, hence electron diffraction.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'Why does electron energy in atoms come in discrete levels?', 'The electron is confined to the atom; standing-wave (de Broglie) conditions allow only certain energies. Transitions between them give photons of specific frequencies (line spectra).', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T5', 'Waves and Particle Nature of Light', 'What evidence supports wave-particle duality?', 'Photoelectric effect (light as photons), electron diffraction (electrons as waves), and Compton scattering all require both wave and particle pictures depending on the experiment.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Define impulse and state the impulse-momentum theorem.', 'Impulse = FΔt = Δp. Impulse equals the change in momentum.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Why are crumple zones effective at reducing injury?', 'They extend Δt during a crash, so for the same Δp the average force F = Δp/Δt is much smaller, reducing the deceleration on the occupants.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'How is a 2D collision analysed?', 'Conserve momentum independently along x and y axes: Σpx_before = Σpx_after, Σpy_before = Σpy_after.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Define angular displacement and angular velocity.', 'Angular displacement θ = arc length / radius (rad). Angular velocity ω = dθ/dt = v/r.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Why is uniform circular motion described as accelerated?', 'Although the speed is constant, the velocity vector continually changes direction, so there is centripetal acceleration a = v^2/r toward the centre.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'A 1500 kg car travels at 20 m s^-1 round a bend of radius 50 m. What centripetal force is required?', 'F = mv^2/r = 1500 × 400/50 = 12 000 N. Provided by friction between tyres and road.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'For an object on a banked track, what does banking achieve?', 'A component of the normal force points centripetally, reducing the friction needed. At the design speed v = √(gr tan θ), no friction is required.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Why does the apparent weight of a passenger change at the top and bottom of a vertical loop?', 'At the top, gravity supplies most of mω^2r, so reaction force is small (or zero in zero-g). At the bottom, the seat must supply mg + mω^2r — apparent weight is higher.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'How is the centripetal force provided for a planet orbiting a star?', 'By the gravitational attraction: GMm/r^2 = mv^2/r, leading to v = √(GM/r) and Kepler''s third law T^2 ∝ r^3.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Define elastic and inelastic collisions in terms of energy.', 'Elastic: KE before = KE after (and momentum conserved). Inelastic: only momentum is conserved; KE is partly converted to heat, sound or deformation.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'A 0.05 kg bullet at 400 m s^-1 embeds in a 2 kg block at rest. Find their common speed.', 'Conserve momentum: 0.05 × 400 = (0.05 + 2) v, so v = 20/2.05 ≈ 9.76 m s^-1.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T6', 'Further Mechanics', 'Why does a rocket accelerate even in vacuum?', 'Newton''s third law: the rocket expels exhaust gases backward, so the gases push the rocket forward. Momentum is conserved: dp_rocket/dt = −v_exhaust × dm/dt.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'State Coulomb''s law in vacuum.', 'F = (1/4πε0) Q1Q2/r^2, with ε0 = 8.85 × 10^-12 F m^-1. Direction along the line of centres.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'How are electric field and potential related?', 'E = −dV/dr (for a radial field). E points down the steepest gradient of V, from high potential to low.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Sketch the field around a positive point charge and a uniform parallel-plate capacitor.', 'Point charge: radial outward arrows. Parallel plates: uniform parallel arrows from + to −, equally spaced (fringing at edges). <svg viewBox="0 0 220 90" width="200" height="80" style="display:block;margin:6px auto"><line x1="20" y1="20" x2="100" y2="20" stroke="#0B1E3F" stroke-width="2"/><line x1="20" y1="70" x2="100" y2="70" stroke="#0B1E3F" stroke-width="2"/><text x="6" y="24" font-size="9" fill="#0B1E3F">+</text><text x="6" y="74" font-size="9" fill="#0B1E3F">−</text><line x1="35" y1="22" x2="35" y2="68" stroke="#0B1E3F" stroke-width="1"/><polygon points="35,68 33,62 37,62" fill="#0B1E3F"/><line x1="55" y1="22" x2="55" y2="68" stroke="#0B1E3F" stroke-width="1"/><polygon points="55,68 53,62 57,62" fill="#0B1E3F"/><line x1="75" y1="22" x2="75" y2="68" stroke="#0B1E3F" stroke-width="1"/><polygon points="75,68 73,62 77,62" fill="#0B1E3F"/><circle cx="170" cy="45" r="5" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="1.5"/><text x="167" y="49" font-size="9" fill="#0B1E3F">+</text><line x1="174" y1="45" x2="200" y2="45" stroke="#0B1E3F" stroke-width="1"/><line x1="170" y1="40" x2="170" y2="20" stroke="#0B1E3F" stroke-width="1"/><line x1="166" y1="45" x2="140" y2="45" stroke="#0B1E3F" stroke-width="1"/><line x1="170" y1="50" x2="170" y2="75" stroke="#0B1E3F" stroke-width="1"/></svg>', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Define capacitance.', 'C = Q/V (farad). For parallel plates C = ε0 ε_r A/d.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Why is the energy stored on a capacitor (1/2)QV and not QV?', 'As charge accumulates, the pd grows from 0 to V, so the average pd during charging is V/2. Energy = average pd × charge = (1/2)QV.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Combine capacitors in series and parallel.', 'Series: 1/C = 1/C1 + 1/C2 + ... Parallel: C = C1 + C2 + ... (opposite to resistors).', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'State the time constant for a capacitor-resistor circuit.', 'τ = RC. After time τ during discharge the charge has fallen to e^-1 ≈ 37% of its initial value.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Define magnetic flux density.', 'B is the force per unit current per unit length on a current-carrying conductor at right angles to the field: F = BIL. Unit: tesla (T).', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Give the force on a charge moving through a magnetic field.', 'F = Bqv sin θ, where θ is the angle between v and B. The force is always perpendicular to v, so the speed is constant and the path is circular when v ⊥ B.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Show that a charged particle moving perpendicular to B follows a circle.', 'The magnetic force Bqv provides the centripetal force mv^2/r, so r = mv/(Bq). Heavier or faster particles trace larger circles.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Define magnetic flux and flux linkage.', 'Φ = BA cos θ (Wb). Flux linkage = NΦ for a coil of N turns.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T7', 'Electric and Magnetic Fields', 'Combine Faraday''s and Lenz''s laws into a single equation.', 'ε = −dΦ/dt for one loop, or ε = −d(NΦ)/dt for a coil of N turns. The minus sign expresses Lenz''s law.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'What did the Rutherford alpha-scattering experiment show?', 'A small dense positive nucleus with most of the atom''s mass; the rest is empty space. Refuted the plum-pudding model.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'What is the closest distance of approach in alpha scattering?', 'When all the alpha''s KE is converted to electrostatic PE: (1/2)mv^2 = kQ_α Q_N/r_min. r_min gives an upper bound on nuclear size.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'Give the quark composition of common baryons and mesons.', 'Proton uud, neutron udd. π+ = ud̄, π− = ūd, π0 = (uū − dd̄)/√2, K+ = us̄.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'List the conserved quantities in particle interactions.', 'Charge, baryon number, lepton numbers (per family). Strangeness conserved in strong/EM but can change by ±1 in weak.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'Why was the neutrino postulated?', 'To conserve energy-momentum and lepton number in beta decay, where the observed continuous β-energy spectrum required a third, undetected particle.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'How is the de Broglie wavelength used to probe nuclei?', 'Accelerate electrons to high energy so λ = h/p ≪ nuclear diameter. Diffraction minima from nuclei give a direct measure of nuclear radius.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'Why is iron-56 the most stable nucleus?', 'It sits at the peak of the binding-energy-per-nucleon curve. Lighter nuclei gain stability by fusion, heavier nuclei by fission.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'Convert 1 atomic mass unit to energy in MeV.', '1 u = 1.66 × 10^-27 kg → E = mc^2 = 931.5 MeV. Useful for binding-energy calculations.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'State the radioactive decay law and define decay constant.', 'N = N0 e^-λt; A = λN. λ is the probability per second of an individual nucleus decaying. T_½ = ln 2/λ.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'Why are linear accelerators less powerful than synchrotrons for the same energy?', 'A linac has a fixed length, so terminal energy depends on length. A synchrotron loops the particle through the same accelerating cavities many times, with magnetic-field strength rising in step with momentum.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'What does a cloud or bubble chamber show?', 'Charged particle tracks: curvature gives momentum (r = p/(Bq)), spiral direction gives charge sign, track density gives ionisation/charge.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T8', 'Nuclear and Particle Physics', 'How are particles produced from collision energy?', 'In a collision, kinetic energy can be converted to mass via E = mc^2, producing new particle-antiparticle pairs whose total mass-energy ≤ available energy.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Define internal energy.', 'The sum of the random kinetic and potential energies of all the particles in a system. For an ideal gas, U depends only on temperature.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Define specific heat capacity and write the energy equation.', 'c = energy required per kg per K to raise temperature: Q = mcΔθ. Units J kg^-1 K^-1.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Define specific latent heat of fusion and vaporisation.', 'Energy per kg required to change phase at constant temperature. Q = mL_f for solid↔liquid; Q = mL_v for liquid↔gas. L_v > L_f because all intermolecular bonds break.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'State the ideal gas equation in two equivalent forms.', 'pV = nRT (R = 8.31 J K^-1 mol^-1) and pV = NkT (k = 1.38 × 10^-23 J K^-1, N = number of molecules).', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'List the assumptions of kinetic theory of gases.', 'Many identical particles in random motion; volume of particles negligible compared to container; collisions elastic and brief; no intermolecular forces between collisions.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Derive the relationship between pressure and mean square speed.', 'pV = (1/3)Nm<c^2>. Combining with pV = NkT gives (1/2)m<c^2> = (3/2)kT.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Why does temperature in K not °C appear in gas equations?', 'Because the kinetic-energy relationship (1/2)m<c^2> = (3/2)kT requires absolute zero. T(K) = θ(°C) + 273.15.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'How does a Boltzmann factor explain reaction rates and conduction?', 'The fraction of molecules with energy ≥ E is ∝ e^(−E/kT). Small rises in T give large changes in this fraction, so rates and conductivities depend strongly on temperature.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Sketch and interpret a Maxwell-Boltzmann speed distribution.', 'Skewed curve from origin, peaks at most-probable speed, falls off at high speeds. Higher T shifts and broadens the curve to higher speeds.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Why does evaporation cool a liquid?', 'Faster molecules escape from the surface, leaving slower ones behind. Mean KE — and so temperature — of the liquid falls.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'A 0.10 kg block of ice at 0 °C is melted using 33 kJ. Calculate L_f.', 'L_f = Q/m = 33 000/0.10 = 3.3 × 10^5 J kg^-1, in line with the accepted value for water.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T9', 'Thermodynamics', 'Why does the temperature of a substance not change during a phase change?', 'All supplied energy goes into breaking intermolecular bonds (increasing potential energy of the particles), not increasing their kinetic energy.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T10', 'Space', 'Define luminosity and intensity.', 'Luminosity L = total power radiated by a star (W). Intensity I = power per unit area received: I = L/(4πd^2).', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'State Stefan''s law for a black body.', 'L = σ A T^4, where σ = 5.67 × 10^-8 W m^-2 K^-4. Doubling T multiplies luminosity by 16.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'State Wien''s displacement law.', 'λ_max T = 2.90 × 10^-3 m K. Hotter bodies peak at shorter wavelengths (bluer).', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'How is parallax used to measure stellar distance?', 'Measure the apparent shift of a nearby star against background stars over six months. Distance d (parsecs) = 1/p (arcseconds).', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'What is the parsec?', 'The distance at which 1 AU subtends an arc of 1 arcsecond. 1 pc = 3.086 × 10^16 m ≈ 3.26 light-years.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'How are standard candles used for cosmic distances?', 'Objects of known L (e.g. Type Ia supernovae, Cepheid variables) allow d to be found from measured intensity via I = L/(4πd^2).', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'Describe the Hertzsprung-Russell diagram.', 'A plot of luminosity (or absolute magnitude) versus surface temperature. Most stars sit on the main sequence; giants/supergiants top right; white dwarfs bottom left.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'Outline the life cycle of a Sun-like star.', 'Protostar → main sequence (H fusion) → red giant (He core) → planetary nebula → white dwarf cooling forever.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'Outline the late evolution of a star with mass > 8 M_sun.', 'Red supergiant building heavier elements up to iron, then core collapse → Type II supernova → neutron star (or black hole if > ~25 M_sun core).', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'Define redshift z and the Doppler formula.', 'z = Δλ/λ ≈ v/c for v ≪ c. Galaxies recede from us, redshifting their spectra.', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'State Hubble''s law.', 'v = H0 d, where H0 ≈ 70 km s^-1 Mpc^-1. Galaxies recede at speeds proportional to distance — evidence for an expanding universe.', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T10', 'Space', 'Give two pieces of evidence for the Big Bang.', 'Hubble redshift expansion; cosmic microwave background at 2.7 K matching predicted blackbody radiation; relative abundance of H/He matching primordial nucleosynthesis.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'Compare the penetrating power of α, β and γ.', 'α: stopped by paper or a few cm of air. β: stopped by ~3 mm of aluminium. γ: never fully stopped, attenuated by lead/concrete.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'How is background radiation accounted for in experiments?', 'Measure background count rate over a long time without the source, then subtract from each measured count rate.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'How do you write a balanced α-decay equation? Use ^238_92 U as example.', '^238_92 U → ^234_90 Th + ^4_2 He. A decreases by 4, Z by 2.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'Write a balanced β− decay equation.', '^14_6 C → ^14_7 N + ^0_-1 e + ν̄_e. Z increases by 1, A unchanged.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'How does γ emission differ from α and β?', 'γ is electromagnetic radiation; emission does not change A or Z. It usually follows α or β decay as the daughter nucleus de-excites.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'State the radioactive decay law and the meaning of λ.', 'dN/dt = −λN; N = N0 e^-λt. λ is the decay constant — probability per unit time of decay for a single nucleus.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'Express activity in two equivalent ways.', 'A = λN = A0 e^-λt. Unit: becquerel (Bq). Activity halves each half-life.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'A radioactive sample has T_½ = 8 days and initial activity 800 Bq. What is the activity after 24 days?', '24 days = 3 half-lives, so A = 800/2^3 = 100 Bq.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'Define absorbed dose and dose equivalent.', 'Absorbed dose D = E/m (Gy = J kg^-1). Dose equivalent H = DQ (Sv), with Q the radiation quality factor.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'Why is α more dangerous internally than externally?', 'Externally, α is stopped by skin. Internally, its very high ionisation density causes severe local cell damage (Q ≈ 20 vs 1 for γ).', 10, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'How is carbon-14 used to date organic remains?', 'Living organisms have a constant C-14:C-12 ratio. After death C-14 decays with T_½ = 5730 yr; the residual ratio gives age via t = (1/λ) ln(N0/N).', 11, 'alevel'),
  ('Physics', 'Edexcel', 'T11', 'Nuclear Radiation', 'How is technetium-99m used in medicine?', 'It emits γ-only with a 6-hour half-life — long enough for imaging, short enough to limit dose. Targeted to organs by chemical labels and detected by gamma cameras.', 12, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'State Newton''s law of gravitation.', 'F = Gm1m2/r^2 (attractive). G = 6.67 × 10^-11 N m^2 kg^-2.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'Define gravitational field strength and give two equivalent forms.', 'g = F/m = GM/r^2. Near Earth''s surface g ≈ 9.81 N kg^-1.', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'Why is gravitational potential always negative?', 'V = −GM/r is referenced to V = 0 at infinity. Work must be done against the attractive force to move outward, so a bound mass has negative PE.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'How is escape velocity derived?', 'KE at surface = magnitude of gravitational PE: (1/2)mv_esc^2 = GMm/R, so v_esc = √(2GM/R) ≈ 11.2 km s^-1 for Earth.', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'Derive Kepler''s third law for a circular orbit.', 'GMm/r^2 = mω^2 r → ω^2 = GM/r^3 → T^2 = (4π^2/GM) r^3.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'What is a geostationary satellite and where does it orbit?', 'Period 24 hours, equatorial, prograde. Altitude ≈ 35 800 km above Earth''s surface. Used for telecommunications and TV.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'How does gravitational field strength vary inside a uniform spherical planet?', 'g ∝ r inside (only mass within radius r contributes), maximum at the surface, then g ∝ 1/r^2 outside.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'Give the work done moving mass m from r1 to r2 in a gravitational field.', 'W = m(V2 − V1) = GMm(1/r1 − 1/r2). Positive if r2 > r1 (work against gravity).', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'How do equipotential surfaces relate to field lines?', 'They are perpendicular to the field lines everywhere. No work is done moving along an equipotential.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T12', 'Gravitational Fields', 'Compare gravitational and electric fields.', 'Both follow inverse-square laws. Gravity acts on mass and is always attractive; electric forces act on charge and can be either. Gravity is much weaker but cumulative.', 10, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'Define simple harmonic motion.', 'Motion in which a = −ω^2 x — acceleration proportional to displacement from equilibrium and directed back toward equilibrium.', 1, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'Sketch displacement, velocity and acceleration against time for SHM starting at x = A.', 'x = A cos(ωt) — cosine. v = −Aω sin(ωt) — sine, leading x by π/2. a = −Aω^2 cos(ωt) — antiphase with x. <svg viewBox="0 0 200 80" width="180" height="70" style="display:block;margin:6px auto"><line x1="10" y1="40" x2="190" y2="40" stroke="#0B1E3F" stroke-width="0.7"/><path d="M10,40 Q35,10 60,40 Q85,70 110,40 Q135,10 160,40 Q175,55 190,42" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="160" y="14" font-size="9" fill="#0B1E3F">x(t)</text></svg>', 2, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'Give the speed of an SHM oscillator at displacement x.', 'v = ±ω √(A^2 − x^2). Maximum at x = 0 (v_max = Aω), zero at x = ±A.', 3, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'State the period of a simple pendulum.', 'T = 2π √(L/g), valid for small angles (< ~10°).', 4, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'State the period of a mass on a spring.', 'T = 2π √(m/k). Independent of amplitude provided Hooke''s law holds.', 5, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'How are KE and PE distributed during SHM?', 'They oscillate at twice the frequency of x. Total energy E = (1/2)kA^2 is constant; KE and PE swap as the oscillator moves through equilibrium.', 6, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'Distinguish light, heavy and critical damping.', 'Light: oscillation with slowly decaying amplitude. Heavy/over: system returns to equilibrium slowly without oscillating. Critical: returns to equilibrium in the shortest time without oscillating — used in car suspensions and door closers.', 7, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'What is resonance and when does it occur?', 'When a driving frequency matches the system''s natural frequency, energy transfer is maximum and amplitude grows large. Damping lowers and broadens the resonance peak.', 8, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'Give one beneficial and one harmful example of resonance.', 'Beneficial: MRI scanners, microwave ovens, musical instruments. Harmful: bridge collapses (Tacoma Narrows), structural failure in earthquakes, vibrating loose components.', 9, 'alevel'),
  ('Physics', 'Edexcel', 'T13', 'Oscillations', 'Why is the period of a simple pendulum independent of mass?', 'Because the restoring force (mg sin θ) is proportional to mass, but inertia is also proportional to mass — they cancel in F = ma.', 10, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'Distinguish random and systematic errors.', 'Random: scatter about the true value, reduced by averaging. Systematic: a consistent offset (zero error, calibration), not reduced by averaging — must be eliminated by recalibrating or zeroing.', 1, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'Define accuracy and precision.', 'Accuracy: closeness to the true value. Precision: small spread among repeated readings (low random uncertainty). A precise instrument can still be inaccurate.', 2, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How is the absolute uncertainty in a single analogue reading estimated?', 'Half the smallest scale division. For a metre rule (mm divisions): ±0.5 mm.', 3, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How is uncertainty in a digital reading estimated?', '±1 in the last displayed digit. A meter reading 12.34 V has uncertainty ±0.01 V.', 4, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How are percentage uncertainties combined for products and quotients?', 'Add them: for P = IV, %u(P) = %u(I) + %u(V).', 5, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How does uncertainty propagate through a power?', 'Multiply the percentage uncertainty in the base by the magnitude of the power: %u(x^n) = |n| × %u(x).', 6, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'When timing oscillations, why time many periods rather than one?', 'The reaction-time uncertainty is roughly the same whether you time 1 or 20 periods, so the percentage uncertainty in the period is divided by 20.', 7, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'Why use a fiducial marker when timing a pendulum?', 'It gives a clear reference point (usually the equilibrium position) where the pendulum is moving fastest, so timing is most consistent and whole oscillations are easily counted.', 8, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How is the uncertainty in a gradient found from a best-fit line?', 'Draw the steepest and shallowest reasonable lines through the error bars. Uncertainty in gradient = (gradient_max − gradient_min)/2.', 9, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'Why should a line of best fit pass close to the centre of error bars?', 'Each error bar represents the uncertainty range of a point. A good line lies within most bars and represents the underlying trend rather than chasing individual scatter.', 10, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'Why is it better to plot a graph than to take a single mean?', 'A graph reveals the relationship (linear, square, exponential), exposes outliers and systematic offsets (non-zero intercept), and allows uncertainty to be assessed from the spread.', 11, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How do you decide on appropriate significant figures for a final answer?', 'Match the least precise input data — typically 2 or 3 SF. Quoting more SFs implies a precision the data do not support.', 12, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'Why is a vernier or digital calliper preferred over a metre rule for measuring small lengths?', 'Calipers resolve to ±0.02 mm or better, giving a much smaller percentage uncertainty on lengths of a few mm than a rule''s ±0.5 mm.', 13, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'What is meant by validity, reliability and reproducibility?', 'Validity: the experiment measures what it claims to. Reliability: repeats give consistent results. Reproducibility: independent groups get the same result with their own apparatus.', 14, 'alevel'),
  ('Physics', 'OCR A', 'M1', 'Development of Practical Skills', 'How is a percentage difference from a known value used to judge accuracy?', '% diff = |measured − accepted|/accepted × 100. If it lies within the experimental uncertainty, the result is consistent with the accepted value.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'List the SI base units relevant to physics.', 'metre (m), kilogram (kg), second (s), ampere (A), kelvin (K), mole (mol). All other units are derived from these.', 1, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Convert 5 nF to farads in scientific form.', '5 nF = 5 × 10^-9 F. Prefix nano = 10^-9.', 2, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Distinguish a scalar and a vector with examples.', 'Scalar: magnitude only — mass, energy, temperature. Vector: magnitude and direction — velocity, force, momentum.', 3, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'How is the resultant of two vectors at right angles found?', 'Magnitude R = √(A^2 + B^2); direction θ = tan^-1(B/A) from A.', 4, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Resolve a 50 N force at 30° above horizontal.', 'Horizontal component = 50 cos 30° ≈ 43.3 N. Vertical component = 50 sin 30° = 25 N.', 5, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Distinguish random and systematic errors.', 'Random: scatter about true value, reduced by averaging repeats. Systematic: consistent offset (zero error, calibration), not reduced by averaging.', 6, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'How is uncertainty in a power found?', 'Multiply the percentage uncertainty in the base by the magnitude of the power: %u(x^n) = |n| × %u(x).', 7, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'How do you check that an equation is dimensionally consistent?', 'Express each term in SI base units; every additive term must have identical units. Inconsistent equations are wrong; consistent ones might still be wrong.', 8, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'How is the mean and uncertainty of a repeated reading calculated?', 'Mean = sum/N. Uncertainty ≈ (max − min)/2 (range method) or use the standard error for a more rigorous estimate.', 9, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Why should the line of best fit pass through (or near) the centre of the error bars?', 'Each error bar represents the uncertainty range; a good line lies within most bars and minimises the sum of squared deviations.', 10, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'How many significant figures should an answer have?', 'No more than the least precise input data. Quoting more SFs implies a precision the data do not support.', 11, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Why is the metre defined in terms of the speed of light?', 'Because c is exactly fixed (299 792 458 m s^-1). Using c removes any drift in the metre standard with time or location.', 12, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Give the SI units of work and the equivalent base units.', 'Joule (J) = N m = kg m^2 s^-2.', 13, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'Why are vector triangles useful?', 'They allow the resultant of two vectors at any angle to be found graphically (or by sine/cosine rule), and to test whether forces in equilibrium close into a triangle.', 14, 'alevel'),
  ('Physics', 'OCR A', 'M2', 'Foundations of Physics', 'A car travels 30 m east then 40 m north. State its displacement.', 'Magnitude = √(30^2 + 40^2) = 50 m. Bearing = arctan(30/40) = 37° east of north.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Write the four SUVAT equations.', 'v = u + at;  s = ut + (1/2)at^2;  v^2 = u^2 + 2as;  s = (u + v)t/2. Constant acceleration only.', 1, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'How do you analyse a 2D projectile?', 'Resolve initial velocity into horizontal (constant) and vertical (uniformly accelerated under g). Treat the components independently and combine for time, range and trajectory.', 2, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'State Newton''s three laws.', '1) An object continues at rest or constant velocity unless a net force acts. 2) F = ma (or F = dp/dt). 3) Forces come in equal and opposite pairs on different bodies.', 3, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Define linear momentum and state the principle of conservation.', 'p = mv. In a closed system with no external resultant force, total momentum is conserved.', 4, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Distinguish elastic, inelastic and perfectly inelastic collisions.', 'All conserve momentum. Elastic also conserves KE. Inelastic loses some KE. Perfectly inelastic: bodies stick together with maximum KE loss.', 5, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Define work, energy and power.', 'Work W = Fs cos θ (J). Energy = capacity to do work. Power P = W/t = Fv (W).', 6, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'State the principle of conservation of energy.', 'Energy cannot be created or destroyed, only transferred or transformed. Total energy in a closed system is constant.', 7, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Define efficiency.', 'Efficiency = useful energy out / total energy in (× 100 for %). Real machines lose energy to heat, sound and friction.', 8, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'State the principle of moments.', 'For a body in rotational equilibrium, sum of clockwise moments about any point = sum of anticlockwise moments. M = F × perpendicular distance.', 9, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'What is a couple, and how is its torque calculated?', 'Two equal antiparallel forces with different lines of action. Torque = one force × perpendicular separation. Produces pure rotation, no translation.', 10, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'State Hooke''s law.', 'F = kx — extension is proportional to applied force up to the limit of proportionality.', 11, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Define stress, strain and Young modulus.', 'Stress σ = F/A (Pa). Strain ε = ΔL/L (dimensionless). Young modulus E = σ/ε (Pa).', 12, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Calculate the elastic strain energy of a spring with k = 200 N m^-1 stretched 0.05 m.', 'E = (1/2)kx^2 = (1/2)(200)(0.05)^2 = 0.25 J.', 13, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Distinguish brittle and ductile materials.', 'Brittle: little plastic deformation; fractures at elastic limit (glass, ceramics). Ductile: significant plastic flow before failure (copper, mild steel) — can be drawn into wires.', 14, 'alevel'),
  ('Physics', 'OCR A', 'M3', 'Forces and Motion', 'Why does a falling parachutist reach a terminal velocity?', 'Drag rises with speed until it equals weight; net force then = 0 and acceleration = 0. Opening the parachute increases drag, lowering the new terminal velocity.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State the equation linking current to drift velocity.', 'I = nAvq, where n is the number density of charge carriers, A the cross-sectional area, v the drift velocity, q the charge per carrier.', 1, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State Ohm''s law and its limits.', 'For an ohmic conductor at constant temperature, V = IR. Fails for non-ohmic components like filament lamps, diodes and thermistors.', 2, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Define resistivity and give the formula.', 'ρ = RA/L (Ω m). Property of the material at a given temperature.', 3, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Sketch the I-V characteristics of a metallic resistor and a filament lamp.', 'Resistor: straight line through origin (constant R). Filament lamp: curve through origin, flatter at higher V (R rises with T).', 4, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State Kirchhoff''s laws.', 'KCL: ΣI_in = ΣI_out at any junction. KVL: ΣEMF = ΣIR around any closed loop.', 5, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Combine three identical 6 Ω resistors in parallel.', '1/R = 3/6, so R = 2 Ω.', 6, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Define EMF and explain the role of internal resistance.', 'EMF = energy supplied per coulomb (J C^-1 = V). Internal resistance r causes a "lost volts" drop Ir, so terminal pd V = ε − Ir.', 7, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'How does a potential divider work?', 'Two resistors in series across a supply produce V_out = V_in × R2/(R1 + R2). Used to scale voltage or as a sensor circuit with thermistor/LDR.', 8, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Distinguish transverse and longitudinal waves.', 'Transverse: oscillation perpendicular to energy transfer (light, water). Longitudinal: oscillation parallel to energy transfer (sound, P-waves).', 9, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State the conditions for two-source interference.', 'Sources must be coherent (constant phase difference, same frequency) and waves of similar amplitude meet at the observation point.', 10, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State the Young''s double-slit equation.', 'w = λD/s. Fringe spacing w grows with wavelength λ and slit-screen distance D, and shrinks with slit separation s.', 11, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State the diffraction grating equation.', 'd sin θ = nλ, where d is slit spacing and n is the order of the maximum.', 12, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Why does the photoelectric effect refute the wave model?', 'No emission below the threshold frequency f0 even at high intensity, and emission is instantaneous. Wave theory predicts emission depends on intensity and a build-up time. Einstein''s photon model (hf = φ + KE_max) explains both.', 13, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'State the de Broglie wavelength formula.', 'λ = h/p. Particles have an associated wavelength; significant when λ is comparable to atomic spacings.', 14, 'alevel'),
  ('Physics', 'OCR A', 'M4', 'Electrons, Waves and Photons', 'Why are LEDs used as cheap photon-energy demonstrations?', 'The threshold voltage V_t at which an LED just lights gives photon energy: eV_t ≈ hc/λ, so Planck''s constant can be measured from V_t for several colours.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Define angular velocity.', 'ω = Δθ/Δt = 2π/T = v/r (rad s^-1).', 1, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Give the centripetal acceleration and force.', 'a = v^2/r = ω^2 r, directed toward the centre. F = ma = mv^2/r.', 2, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Define simple harmonic motion.', 'a = −ω^2 x. Acceleration is proportional to displacement and directed toward equilibrium.', 3, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Give T for a simple pendulum and a mass-spring oscillator.', 'Pendulum: T = 2π √(L/g) (small angles). Spring: T = 2π √(m/k).', 4, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Distinguish damping types.', 'Light damping: slow decay of amplitude. Critical damping: fastest return to equilibrium without oscillation. Heavy/over: slow non-oscillatory return.', 5, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Define internal energy.', 'Sum of random KE and PE of all particles in a system. For an ideal gas it is purely kinetic and depends only on T.', 6, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'State the ideal gas equation.', 'pV = nRT = NkT, where n is moles, N is number of particles, R = 8.31 J K^-1 mol^-1, k = 1.38 × 10^-23 J K^-1.', 7, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'State Newton''s law of gravitation.', 'F = Gm1m2/r^2, attractive. G = 6.67 × 10^-11 N m^2 kg^-2.', 8, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Derive Kepler''s third law.', 'GMm/r^2 = mω^2 r → T^2 = (4π^2/GM) r^3.', 9, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Outline a Sun-like star''s evolution.', 'Protostar → main sequence (H fusion) → red giant → planetary nebula → white dwarf cooling forever.', 10, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'State Stefan''s and Wien''s laws.', 'Stefan: L = σ A T^4. Wien: λ_max T = 2.90 × 10^-3 m K. Hot stars are luminous and blue.', 11, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'How is a Hertzsprung-Russell diagram constructed?', 'Plot luminosity (or absolute magnitude) vertically against decreasing surface temperature horizontally. Main sequence runs diagonally; giants top right; white dwarfs bottom left.', 12, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'State Hubble''s law and its implication.', 'v = H0 d. Linear redshift-distance relation implies the universe is expanding from a hot, dense past (Big Bang).', 13, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'Give two pieces of evidence for the Big Bang.', 'Hubble redshift; the cosmic microwave background at 2.7 K; primordial H/He ratio matching nucleosynthesis predictions.', 14, 'alevel'),
  ('Physics', 'OCR A', 'M5', 'Newtonian World and Astrophysics', 'What is dark energy?', 'A hypothetical component (~68% of the universe) driving accelerating expansion of space, inferred from Type Ia supernova distances and CMB measurements.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Define electric field strength.', 'E = F/Q, force per unit positive test charge (N C^-1 = V m^-1).', 1, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'State Coulomb''s law.', 'F = (1/4πε0) Q1Q2/r^2. Like charges repel, unlike attract.', 2, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Define capacitance and the energy stored on a capacitor.', 'C = Q/V. W = (1/2)QV = (1/2)CV^2.', 3, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Give the discharge equation for a capacitor through a resistor.', 'Q = Q0 e^-t/(RC). Time constant τ = RC; after τ the charge has fallen to ~37% of initial.', 4, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Give the magnetic force on a moving charge.', 'F = Bqv sin θ. When v ⊥ B, charged particle motion is circular with r = mv/(Bq).', 5, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'State Faraday''s law of induction.', 'EMF = −d(NΦ)/dt. The induced EMF equals the negative rate of change of flux linkage. Lenz: minus sign.', 6, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Outline how an ideal transformer works.', 'AC primary current creates a changing flux in the iron core, inducing an EMF in the secondary coil. V_p/V_s = N_p/N_s; for ideal: V_p I_p = V_s I_s.', 7, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Compare ranges of α, β and γ.', 'α: a few cm in air, stopped by paper. β: ~1 m in air, stopped by a few mm of aluminium. γ: many metres, attenuated by lead/concrete.', 8, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'State the radioactive decay law.', 'N = N0 e^-λt; A = λN. Half-life T_½ = ln 2/λ.', 9, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Why does fission of U-235 release energy?', 'The fragments lie nearer the peak of the binding-energy-per-nucleon curve, so binding energy per nucleon increases — the difference is released as KE, γ and neutrons (~200 MeV per fission).', 10, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'How does an X-ray tube produce X-rays?', 'Electrons are accelerated through a high pd (~50–150 kV) and strike a metal target. Sudden deceleration produces bremsstrahlung; characteristic lines come from inner-shell transitions.', 11, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'How does a CT scanner improve on a planar X-ray?', 'It rotates the tube around the patient and uses computer reconstruction to produce 3D cross-sectional images, distinguishing soft tissues better.', 12, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'How does ultrasound imaging work?', 'A piezoelectric transducer emits short MHz pulses; reflections at tissue boundaries return at a time t giving depth d = vt/2 (using the speed in tissue ~1540 m s^-1).', 13, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'How does PET imaging work?', 'A β+ emitter (e.g. F-18 in FDG) is injected. Each positron annihilates with an electron, producing two back-to-back 511 keV γ photons detected in coincidence to localise activity.', 14, 'alevel'),
  ('Physics', 'OCR A', 'M6', 'Particles and Medical Physics', 'Why is technetium-99m widely used in medical imaging?', 'It is a pure γ emitter (no α or β to damage tissue), with a 6-hour half-life — long enough for imaging, short enough to limit dose.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Distinguish random and systematic errors.', 'Random: scatter about the true value (reduced by averaging repeats). Systematic: a constant offset that is not reduced by repeating — eliminated by recalibrating or correcting for zero error.', 1, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Define accuracy and precision.', 'Accuracy: closeness of a measurement to the true value. Precision: closeness of repeated readings to one another, independent of accuracy.', 2, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'How is uncertainty in a single reading estimated?', 'Analogue: half the smallest scale division. Digital: ±1 in the last displayed digit.', 3, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'How are percentage uncertainties combined?', 'Sums/differences: add absolute uncertainties. Products/quotients: add percentage uncertainties. Powers: multiply percentage uncertainty by the power.', 4, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'How is the uncertainty in a gradient determined?', 'Draw the steepest and shallowest plausible best-fit lines through the error bars; half their gradient difference is the gradient uncertainty.', 5, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Why log a non-linear relationship before plotting?', 'For y = kx^n, log y = log k + n log x is linear. The gradient gives n and the intercept gives log k, allowing the relationship to be checked and parameters extracted.', 6, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Why use a fiducial marker for timing oscillations?', 'It defines a fixed reference at the equilibrium position (where speed is greatest), giving the most consistent point to start and stop the timer.', 7, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Why time many periods rather than one when measuring T?', 'Reaction-time uncertainty is roughly fixed; timing 20 periods divides the percentage uncertainty by 20.', 8, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Define validity, reliability, and reproducibility.', 'Validity: the experiment measures what it claims to. Reliability: repeats give consistent values. Reproducibility: independent groups get the same result with different apparatus.', 9, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Distinguish a control variable from an independent and dependent variable.', 'Independent: deliberately varied. Dependent: measured in response. Control: held constant so it does not confound the relationship.', 10, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'How should significant figures be chosen for a final answer?', 'No more than the least precise input data — usually 2 or 3 SF in A-level practicals.', 11, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'Why are vernier callipers or micrometers preferred over a metre rule for small lengths?', 'They resolve to ±0.02 mm or ±0.01 mm, giving a much smaller percentage uncertainty than a rule''s ±0.5 mm on small distances.', 12, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'What is the role of peer review in physics?', 'Independent experts evaluate methods, statistics and conclusions before publication, exposing errors and weak claims and improving the rigour of the scientific record.', 13, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'How is a percentage difference from a known value used to judge an experiment?', '% diff = |measured − accepted|/accepted × 100. If it lies within the propagated experimental uncertainty, the result is consistent with the accepted value.', 14, 'alevel'),
  ('Physics', 'OCR B', 'B1', 'Development of Practical Skills', 'When is a result deemed an "outlier"?', 'When it lies more than ~2 standard deviations from the mean (or clearly off the trend on a graph). It can be re-checked, repeated, or excluded with justification — never silently dropped.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How do you decide whether two quantities are linearly related?', 'Plot one against the other; a straight line through the origin (within error bars) supports y ∝ x. Non-linear data may fit y = kx^n — confirm by plotting log y vs log x.', 1, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'For y = kx^n, how is n found graphically?', 'Take logs: log y = n log x + log k. Plot log y against log x; the gradient is n and the y-intercept is log k.', 2, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'For y = A e^(kx), how is k found graphically?', 'Take natural logs: ln y = kx + ln A. Plot ln y against x; the gradient is k and the y-intercept is ln A.', 3, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How is a half-life found from a decay graph?', 'Read the time taken for activity (or count rate) to halve from any initial value — repeating from several starting points and averaging gives a more reliable T_½.', 4, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How are percentage uncertainties combined?', 'Add them for products and quotients. Multiply by the power for x^n. For sums and differences, add absolute uncertainties.', 5, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'What does a non-zero y-intercept on an expected-through-origin graph indicate?', 'A systematic error — typically a zero offset or background reading that was not subtracted before plotting.', 6, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'Why are error bars drawn on graphs?', 'To show the uncertainty in each measurement so the reader can judge whether the line of best fit is consistent with the data and how to estimate gradient/intercept uncertainty.', 7, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How should you handle an outlier on a graph?', 'Re-check the original measurement; if confirmed and unexplained, repeat the data point. Only exclude with justification — never silently delete.', 8, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'Why scale a graph to fill more than half of each axis?', 'It maximises precision when reading values, makes scatter and trends visible, and reduces the percentage uncertainty in any gradient or intercept reading.', 9, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'When data span several orders of magnitude, what plot is appropriate?', 'A logarithmic scale (semi-log or log-log). It compresses the range so that exponential or power relationships appear as straight lines.', 10, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How is the standard error of the mean estimated?', 'σ_mean = σ/√N, where σ is the sample standard deviation and N is the number of repeats. Doubling N improves the standard error by a factor √2.', 11, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'Why is ln 2 ≈ 0.693 useful in radioactive decay?', 'Because T_½ = ln 2 / λ. Knowing the half-life and using λ = 0.693/T_½ allows N = N0 e^(−λt) to be evaluated.', 12, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How do you find the gradient at a single point on a curve?', 'Draw a tangent at that point; the gradient of the tangent is dy/dx at that point. Use a long tangent line for a more accurate reading.', 13, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'How is the area under a curve interpreted physically?', 'For a velocity-time graph it is displacement; for a force-distance graph it is work done; for I-t graph it is charge. Area = sum of (y × Δx) integrated along x.', 14, 'alevel'),
  ('Physics', 'OCR B', 'B2', 'Fundamental Data Analysis', 'When can a linear regression line be trusted?', 'When residuals scatter randomly about the line with no pattern, error bars span the line, and the assumed model (linear, power, exponential) is supported by the underlying physics.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'How is a digital image represented?', 'A 2D array of pixels; each pixel holds one or more numerical values for brightness/colour. Resolution and bit depth control image quality and file size.', 1, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'Define resolution and contrast in imaging.', 'Resolution: the smallest separation that can be distinguished. Contrast: the difference in signal between adjacent regions, often expressed as (I_max − I_min)/(I_max + I_min).', 2, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'How is an analogue signal converted to digital?', 'Sample at regular intervals (sampling rate ≥ 2× highest frequency, Nyquist) and quantise each sample to a finite number of levels (bit depth).', 3, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'State the relationship I = nAvq for current.', 'Current = number density × cross-section × drift velocity × charge per carrier. Underpins how I depends on material and geometry.', 4, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'State Ohm''s law and define resistance.', 'V = IR for an ohmic conductor at constant T. Resistance R = V/I (Ω).', 5, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'Why does a metal''s resistance increase with T?', 'Lattice ions vibrate more vigorously, increasing the rate of electron-ion collisions and reducing drift velocity for a given E-field.', 6, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'Define resistivity.', 'ρ = RA/L (Ω m). Property of the material at a given temperature.', 7, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'Define stress, strain and the Young modulus.', 'σ = F/A (Pa). ε = ΔL/L. E = σ/ε (Pa) — gradient of the elastic part of the stress-strain graph.', 8, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'Distinguish brittle, ductile and tough materials.', 'Brittle: little plastic strain (glass). Ductile: large plastic strain before failure (copper). Tough: high energy absorbed before fracture (rubber, mild steel).', 9, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'How is the wave equation written, and what does each term mean?', 'v = fλ. v = wave speed (m s^-1), f = frequency (Hz), λ = wavelength (m).', 10, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'How is a digital image compressed using lossless methods?', 'Run-length encoding compresses runs of identical pixels; entropy coding (Huffman) gives shorter codes to common values. The original is exactly recoverable.', 11, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'How does JPEG (lossy) compression work in outline?', 'Convert to YCbCr, split into 8×8 blocks, apply DCT, quantise frequency components (discarding fine detail), then entropy-code. Small perceptual loss for large size savings.', 12, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'State the relationship between number of bits b and discrete levels L.', 'L = 2^b. 8 bits give 256 levels per channel; 24 bits per pixel = ~16 million colours.', 13, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'Compare conductors, semiconductors and insulators.', 'Conductors: many free carriers, low ρ. Semiconductors: few carriers, ρ falls strongly with T. Insulators: very few carriers, ρ very high. Determined by the band gap.', 14, 'alevel'),
  ('Physics', 'OCR B', 'B3', 'Physics in Action', 'How does an LDR work?', 'Light raises electrons across the band gap of the semiconductor, increasing carrier density and reducing resistance. Used in light-sensing potential dividers.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the principle of superposition.', 'When two waves overlap, the resultant displacement at a point is the vector sum of their individual displacements at that instant.', 1, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'Define path difference and the conditions for constructive/destructive interference.', 'Path difference = difference in distance from the two sources. Constructive: nλ. Destructive: (n + 1/2)λ.', 2, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the Young''s double-slit fringe equation.', 'w = λD/s. Fringe spacing depends on wavelength, slit-to-screen distance and slit separation.', 3, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the diffraction grating equation.', 'd sin θ = nλ. With many slits, maxima are sharp and intensity grows as N^2.', 4, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State Snell''s law.', 'n1 sin θ1 = n2 sin θ2. Light bends toward the normal entering a denser medium (n2 > n1).', 5, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'Define refractive index.', 'n = c/v, where c is the speed of light in vacuum and v in the medium. Always ≥ 1.', 6, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'What conditions give total internal reflection?', 'Light travelling in the denser medium hits the boundary at an angle ≥ critical angle θc, where sin θc = n2/n1.', 7, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the photon-energy equation.', 'E = hf = hc/λ. h = 6.63 × 10^-34 J s.', 8, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the photoelectric equation.', 'hf = φ + KE_max. Below the threshold f0 = φ/h, no photoelectrons are emitted however intense the light.', 9, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the de Broglie wavelength formula.', 'λ = h/p. Predicts wave behaviour for particles, confirmed by electron diffraction.', 10, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'How is the path-integral / phasor model used to explain reflection?', 'Each path from source to detector contributes a phasor of the same length; nearby paths add coherently. The path of stationary phase corresponds to angle of incidence = angle of reflection.', 11, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'How does the phasor model explain diffraction at a slit?', 'Phasors from points across the slit add as a polygon. They rotate as the angle θ changes, giving cancellation at sin θ = mλ/a (single-slit minima).', 12, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State the four SUVAT equations and one condition.', 'v = u + at; s = ut + (1/2)at^2; v^2 = u^2 + 2as; s = (u+v)t/2. Constant acceleration.', 13, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'State Newton''s second law in two forms.', 'F = ma (constant mass); F = dp/dt (general). The second form is needed for variable-mass problems (rockets).', 14, 'alevel'),
  ('Physics', 'OCR B', 'B4', 'Understanding Processes', 'Define impulse and link it to momentum change.', 'Impulse = FΔt = ∫F dt = Δp. Long contact times reduce force for the same momentum change — basis of crumple zones, airbags, padding.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Define angular speed.', 'ω = Δθ/Δt = 2π/T = v/r (rad s^-1).', 1, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'State centripetal acceleration and force.', 'a = v^2/r = ω^2 r toward the centre. F = ma = mv^2/r supplied by tension, friction, gravity, etc.', 2, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'State Newton''s law of gravitation.', 'F = Gm1m2/r^2 (attractive). G = 6.67 × 10^-11 N m^2 kg^-2.', 3, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Define gravitational field strength.', 'g = F/m = GM/r^2. Near Earth''s surface g ≈ 9.81 N kg^-1.', 4, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Derive Kepler''s third law for a circular orbit.', 'GMm/r^2 = mω^2 r → T^2 = (4π^2/GM) r^3.', 5, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Define simple harmonic motion.', 'a = −ω^2 x. Acceleration proportional to displacement, directed toward equilibrium.', 6, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Give the period of a mass-spring system and a simple pendulum.', 'Spring: T = 2π √(m/k). Pendulum: T = 2π √(L/g) for small angles.', 7, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'How is energy distributed in SHM?', 'Total E = (1/2)kA^2 is constant. KE and PE oscillate at twice the SHM frequency, swapping as the oscillator passes through equilibrium.', 8, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'What is resonance?', 'When the driving frequency matches the natural frequency of an undamped or lightly damped system, energy transfer is maximum and amplitude is large.', 9, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Define internal energy and link it to temperature.', 'U = sum of random KE + PE of all particles. For an ideal gas, U = (3/2)NkT — depends only on T.', 10, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'State the ideal gas equation.', 'pV = nRT = NkT, with R = 8.31 J K^-1 mol^-1, k = 1.38 × 10^-23 J K^-1.', 11, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Why does a small temperature rise sharply increase reaction or evaporation rate?', 'The Boltzmann factor e^(−E/kT) rises rapidly with T, so the fraction of molecules with energy ≥ E increases sharply.', 12, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'State the second law of thermodynamics in plain language.', 'The total entropy of an isolated system never decreases. Heat flows spontaneously from hot to cold, never the reverse.', 13, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Why does evaporation cool a liquid?', 'Higher-energy molecules escape, leaving behind a lower mean KE — and hence lower temperature.', 14, 'alevel'),
  ('Physics', 'OCR B', 'B5', 'Rise and Fall of the Clockwork Universe', 'Define specific heat capacity and specific latent heat.', 'c: energy per kg per K to change temperature, Q = mcΔθ. L: energy per kg to change phase at constant T, Q = mL.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Define electric field strength and potential.', 'E = F/Q (N C^-1). V = W/Q (J C^-1 = V). Related by E = −dV/dr.', 1, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'State Coulomb''s law.', 'F = (1/4πε0) Q1Q2/r^2. ε0 = 8.85 × 10^-12 F m^-1.', 2, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Define capacitance and the energy stored.', 'C = Q/V (F). W = (1/2)CV^2 = (1/2)QV = Q^2/(2C).', 3, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'State the discharge equation for a capacitor.', 'Q = Q0 e^-t/(RC). Time constant τ = RC.', 4, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Define magnetic flux density and the force on a wire.', 'B is force per unit current per unit length, F = BIL sin θ. Unit: tesla (T).', 5, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Give the magnetic force on a moving charge and the radius of its circular path.', 'F = Bqv sin θ; for v ⊥ B, r = mv/(Bq).', 6, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'State Faraday''s and Lenz''s laws together.', 'EMF = −d(NΦ)/dt. Magnitude given by rate of change of flux linkage; sign opposes the change that produced it.', 7, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'How does an ideal transformer relate primary and secondary?', 'V_p/V_s = N_p/N_s; for ideal transformer V_p I_p = V_s I_s.', 8, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'List the conserved quantities in particle interactions.', 'Charge, baryon number, lepton numbers per family, energy/momentum. Strangeness conserved in strong/EM but can change by ±1 in weak.', 9, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Give the quark composition of a proton, neutron and π+.', 'Proton uud; neutron udd; π+ = ud̄.', 10, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'State the radioactive decay law.', 'N = N0 e^-λt; A = λN; T_½ = ln 2/λ.', 11, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Define mass defect and binding energy.', 'Mass defect Δm = mass of separate nucleons − mass of nucleus. Binding energy = Δm c^2 — energy released when the nucleus is assembled, or required to break it apart.', 12, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Why does fission release energy from heavy nuclei?', 'The fragments lie nearer the peak of the binding-energy-per-nucleon curve at iron, so more binding energy is released as KE and γ.', 13, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Why does fusion require very high temperatures?', 'Nuclei must overcome the Coulomb barrier (~MeV) to come close enough for the strong force to bind them. Thermal energies of ~10^7 K are needed.', 14, 'alevel'),
  ('Physics', 'OCR B', 'B6', 'Field and Particle Physics', 'Define dose equivalent and its unit.', 'H = D × Q, where D is absorbed dose in grays and Q is the radiation quality factor (~1 for β/γ, ~20 for α). Unit: sievert (Sv).', 15, 'alevel');
